"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[166457],{785023:e=>{e.exports=JSON.parse('{"tag":{"label":"weather","permalink":"/dst-api-webdocs/docs/tags/weather","allTagsPath":"/dst-api-webdocs/docs/tags","count":46,"items":[{"id":"game-scripts/components/acidinfusible","title":"Acidinfusible","description":"Applies and removes an acid infusion effect based on world rain state and entity rain immunity, adjusting combat stats, movement speed, and visual effects accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/acidinfusible"},{"id":"game-scripts/widgets/beaverbadge","title":"Beaverbadge","description":"Renders the beaver meter UI widget with dynamic arrow animation based on the current sanity level and full moon state.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/beaverbadge"},{"id":"game-scripts/prefabs/beehive","title":"Beehive","description":"Manages hive behavior including bee spawning, seasonal rate adjustments, damage response, hauntable mechanics, and interactions with freezing and burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beehive"},{"id":"game-scripts/components/birdspawner","title":"Birdspawner","description":"Manages the spawning and behavior of birds in the game world, including timed spawning for players, lunar hail event responses, and dynamic environmental adjustments.","permalink":"/dst-api-webdocs/docs/game-scripts/components/birdspawner"},{"id":"game-scripts/prefabs/buzzardspawner","title":"Buzzardspawner","description":"Spawns buzzards in response to environmental conditions and events, managing their lifecycle, shadow proxies, and seasonal behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/buzzardspawner"},{"id":"game-scripts/prefabs/caveacidrain","title":"Caveacidrain","description":"Manages the spawning and rendering of acid rain particles in the game world, including interaction with rain domes and entity pooling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/caveacidrain"},{"id":"game-scripts/components/caveweather","title":"Caveweather","description":"Manages weather simulation including precipitation, moisture, wetness, and associated visual/audio effects in the Cave biome.","permalink":"/dst-api-webdocs/docs/game-scripts/components/caveweather"},{"id":"game-scripts/prefabs/coldfirepit","title":"Coldfirepit","description":"Manages the cold fire pit structure, a weather-resistant campfire that consumes fuel at a variable rate depending on precipitation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/coldfirepit"},{"id":"game-scripts/components/dryer","title":"Dryer","description":"Manages the drying process of ingredients into preserved food products, handling timers, rain exposure, and state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryer"},{"id":"game-scripts/components/dryingrack","title":"Dryingrack","description":"Manages drying behavior for items placed in a container, handling time-based drying, weather effects (rain/acid rain), and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryingrack"},{"id":"game-scripts/components/farming_manager","title":"Farming Manager","description":"Manages soil moisture, nutrients, and farming-related systems across the world map, including plant growth, weed spawning, and Lord Fruit Fly behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farming_manager"},{"id":"game-scripts/components/frograin","title":"Frograin","description":"Manages the spawning and lifecycle of frogs during rainy spring weather, including logic for lunar rift influence and player-specific spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/frograin"},{"id":"game-scripts/brains/hermitcrabbrain","title":"Hermitcrabbrain","description":"Manages the AI behavior tree for the Hermit Crab, including trading, fishing, hotspring soaking, pet feeding, tea shop navigation, and environmental adaptation (weather, day/night).","permalink":"/dst-api-webdocs/docs/game-scripts/brains/hermitcrabbrain"},{"id":"game-scripts/widgets/iceover","title":"IceOver","description":"Manages a visual freeze overlay effect and sound feedback when an entity\'s temperature drops.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/iceover"},{"id":"game-scripts/prefabs/lightning","title":"Lightning","description":"Spawns a temporary visual and audio effect for lightning strikes, including screen flash and camera shake for nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightning"},{"id":"game-scripts/prefabs/lightningrod","title":"Lightningrod","description":"A structure component that accumulates charge during thunderstorms and discharges lightning upon impact, while also acting as a battery and breakable workable object.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightningrod"},{"id":"game-scripts/prefabs/lunarhail","title":"Lunarhail","description":"Manages the visual particle system and splash effects for lunar hail precipitation in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lunarhail"},{"id":"game-scripts/components/lunarhailbuildup","title":"Lunarhailbuildup","description":"Manages the lunar hail buildup mechanic for a structure, tracking accumulation and decay during lunar hail events, and handling work required to remove the buildup.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailbuildup"},{"id":"game-scripts/components/lunarhailmanager","title":"Lunarhailmanager","description":"Manages spawning, physics, and impact behavior of falling debris during lunar hail storms, including damage application, shelter detection, and interaction with the world topology.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailmanager"},{"id":"game-scripts/prefabs/meteorspawner","title":"Meteorspawner","description":"Creates a classified entity that acts as a meteor spawner by attaching the meteorshower component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meteorspawner"},{"id":"game-scripts/prefabs/meteorwarning","title":"Meteorwarning","description":"Renders a fading shadow FX entity that warns players of an incoming meteor impact during meteor showers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meteorwarning"},{"id":"game-scripts/components/moisture","title":"Moisture","description":"Manages a character\'s moisture level, including precipitation absorption, drying rates, waterproofing modifiers, and state transitions like wet or soaked.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moisture"},{"id":"game-scripts/components/moonstormlightningmanager","title":"Moonstormlightningmanager","description":"Manages periodic ground lightning spawns during moonstorms based on player proximity and network node data.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonstormlightningmanager"},{"id":"game-scripts/widgets/moonstormover","title":"Moonstormover","description":"Manages the visual and audio overlay effects during a moonstorm, including screen fading, brightness adjustments, dynamic lighting, and shader-based dust animation.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/moonstormover"},{"id":"game-scripts/components/moonstormwatcher","title":"Moonstormwatcher","description":"Manages moonstorm-related speed penalties for entities based on storm intensity and vision state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonstormwatcher"},{"id":"game-scripts/prefabs/mushroom_farm","title":"Mushroom Farm","description":"Manages the growth, harvesting, and state progression of a mushroom farm structure, including interactions with snow cover, spore conversion, and repair mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_farm"},{"id":"game-scripts/prefabs/oasislake","title":"Oasislake","description":"Represents a dynamic water source in the Desert biome that can dry up during sandstorms and regrow vegetation afterward.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oasislake"},{"id":"game-scripts/prefabs/player_common","title":"Player Common","description":"Central player component implementing shared behaviors, HUD/camera controls, weather effects, seamless swaps, and YOTB skin unlocking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/player_common"},{"id":"game-scripts/prefabs/rain","title":"Rain","description":"Manages in-game rainfall particle effects and raindrop spawning logic using a VFX emitter system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rain"},{"id":"game-scripts/prefabs/raincoat","title":"Raincoat","description":"A wearable item that provides waterproofer protection and insulation while slowly consuming fuel over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/raincoat"},{"id":"game-scripts/components/raindome","title":"Raindome","description":"Manages a dynamic rain-shield dome entity that grants rain immunity to nearby entities within its active radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/raindome"},{"id":"game-scripts/widgets/raindomeover","title":"Raindomeover","description":"Renders a dynamic overlay indicating the influence of active rain domes around the player.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/raindomeover"},{"id":"game-scripts/components/raindomewatcher","title":"Raindomewatcher","description":"Tracks whether an entity is inside a rain dome and notifies the entity upon entering or exiting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/raindomewatcher"},{"id":"game-scripts/prefabs/rainometer","title":"Rainometer","description":"A structure component that tracks local rain levels via animation and responds to player interaction and environmental effects like fire.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rainometer"},{"id":"game-scripts/components/sandstorms","title":"Sandstorms","description":"Manages global sandstorm state and calculates storm intensity based on season, weather, location, and nearby oases.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sandstorms"},{"id":"game-scripts/components/sandstormwatcher","title":"Sandstormwatcher","description":"Manages movement speed penalties during sandstorms based on vision state, mounting, and storm intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sandstormwatcher"},{"id":"game-scripts/components/sheltered","title":"Sheltered","description":"Tracks whether an entity is under cover (e.g., from trees or structures) and manages shelter state transitions, including communication and networking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sheltered"},{"id":"game-scripts/components/snowballmelting","title":"Snowballmelting","description":"Tracks ambient temperature and manages melting state transitions for entities like snowballs in response to environmental conditions and snow cover.","permalink":"/dst-api-webdocs/docs/game-scripts/components/snowballmelting"},{"id":"game-scripts/prefabs/spoiledfood","title":"Spoiledfood","description":"Provides shared initialization logic for spoiled food items used as fertilizer and ocean fishing lures, with weather-sensitive perish behavior and work-based looting for fish variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spoiledfood"},{"id":"game-scripts/brains/tornadobrain","title":"Tornadobrain","description":"Implements decision-making logic for a tornado entity, directing it to move toward or wander near a target location.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/tornadobrain"},{"id":"game-scripts/prefabs/umbrella","title":"Umbrella","description":"An equippable item that provides rain protection, insulation, and temporary coverage, consuming fuel or perishing over time depending on variant.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/umbrella"},{"id":"game-scripts/components/wateryprotection","title":"Wateryprotection","description":"Applies protective effects (withering, cooling, extinguishing, and wetting) to entities within a radius, typically used for environmental interactions like rain or water-based abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wateryprotection"},{"id":"game-scripts/components/weather","title":"Weather","description":"Manages dynamic weather systems including precipitation, temperature, moisture, wetness, snow accumulation, lightning, and atmospheric lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weather"},{"id":"game-scripts/components/witherable","title":"Witherable","description":"Manages cyclic withering and rejuvenation of plants based on temperature and weather conditions, and supports temporary protection periods.","permalink":"/dst-api-webdocs/docs/game-scripts/components/witherable"},{"id":"game-scripts/components/worldmeteorshower","title":"Worldmeteorshower","description":"Controls meteor loot generation logic, including conditional replacement of moon rocks with moon rock shells based on accumulated odds.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldmeteorshower"},{"id":"game-scripts/components/worldstate","title":"Worldstate","description":"Tracks and broadcasts global world state variables such as time, phase, season, weather, and moon cycles for the entire world entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldstate"}],"unlisted":false}}')}}]);